import { execFile as execFileCallback } from 'child_process'
import { promises as fs } from 'fs'
import path from 'path'
import { fileURLToPath } from 'url'
import { promisify } from 'util'

const execFile = promisify(execFileCallback)
const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)
const rootDir = path.resolve(__dirname, '..')
const viteBin = path.join(rootDir, 'node_modules', 'vite', 'bin', 'vite.js')
const configPath = path.join(rootDir, 'renderer', 'vite.mobile-editor.config.js')
const distDir = path.join(rootDir, 'renderer', 'dist-mobile-editor')
const bundlePath = path.join(distDir, 'mobile-editor.js')
const outputDir = path.join(rootDir, 'mobile', 'src', 'generated')
const outputPath = path.join(outputDir, 'editor-web-bundle.ts')

await execFile(process.execPath, [viteBin, 'build', '--config', configPath], {
  cwd: rootDir
})

const bundle = await fs.readFile(bundlePath, 'utf8')
const source = `// Generated by scripts/build-mobile-editor-bundle.js\n// prettier-ignore\nexport const editorWebBundle = ${JSON.stringify(bundle)}\n`

await fs.mkdir(outputDir, { recursive: true })
await fs.writeFile(outputPath, source)
